+function drawStatusEffect(ctx: CanvasRenderingContext2D, state: AnimState, x: number, y: number, s: number, frame: number) {
+  if (state === 'working') {
+    // Glow effect: pulsating golden squares orbiting character
+    for (let i = 0; i < 3; i++) {
+      const angle = (frame * 0.08 + i * 2.1) % (Math.PI * 2);
+      const sx = x + 8 * s + Math.cos(angle) * 12 * s;
+      const sy = y + 10 * s + Math.sin(angle) * 8 * s;
+      const size = (Math.sin(frame * 0.15 + i) * 0.5 + 1) * s;
+      ctx.fillStyle = P.gold[3 + (i % 2)];
+      ctx.fillRect(sx, sy, size, size);
+    }
+  } else if (state === 'idle') {
+    // ZZZ particles rising above character
+    const particleCount = 3;
+    for (let i = 0; i < particleCount; i++) {
+      const px = x + 8 * s + (Math.sin(frame * 0.05 + i) * 4) * s;
+      const py = y - 8 * s - (frame * 0.5 + i * 10) % 20;
+      ctx.fillStyle = `rgba(200, 200, 255, ${(20 - ((frame * 0.5 + i * 10) % 20)) / 20})`;
+      ctx.font = `${8 * s}px monospace`;
+      ctx.fillText('Z', px, py);
+    }
+  } else if (state === 'stalled') {
+    // Exclamation mark with pulsing red background
+    const pulse = Math.sin(frame * 0.12) * 0.25 + 0.25;
+    ctx.fillStyle = `rgba(231, 76, 60, ${pulse})`;
+    ctx.fillRect(x - s, y - 2 * s, 18 * s, 24 * s);
+    ctx.fillStyle = '#e74c3c';
+    ctx.font = `bold ${10 * s}px sans-serif`;
+    ctx.fillText('!', x + 14 * s, y + 4 * s);
+  } else if (state === 'processing') {
+    // Spinning gears animation around character
+    const gearCount = 2;
+    for (let i = 0; i < gearCount; i++) {
+      const angle = (frame * 0.1 + i * Math.PI) % (Math.PI * 2);
+      const cx = x + 8 * s + Math.cos(angle) * 14 * s;
+      const cy = y + 10 * s + Math.sin(angle) * 10 * s;
+      drawGear(ctx, cx, cy, 6 * s, angle);
+    }
+  } else if (state === 'reviewing') {
+    ctx.strokeStyle = P.gold[2]; ctx.lineWidth = 1.5;
+    ctx.beginPath(); ctx.arc(x + 16 * s, y + 2 * s, 3 * s, 0, Math.PI * 2); ctx.stroke();
+    ctx.beginPath(); ctx.moveTo(x + 18 * s, y + 4 * s); ctx.lineTo(x + 20 * s, y + 6 * s); ctx.stroke();
+  } else if (state === 'cancelled') {
+    ctx.fillStyle = 'rgba(50, 50, 60, 0.4)';
+    ctx.fillRect(x - s, y - 2 * s, 18 * s, 24 * s);
+  }
+}
+
+function drawGear(ctx: CanvasRenderingContext2D, cx: number, cy: number, radius: number, rotation: number) {
+  ctx.save();
+  ctx.translate(cx, cy);
+  ctx.rotate(rotation);
+  ctx.fillStyle = '#888888';
+  ctx.strokeStyle = '#555555';
+  ctx.lineWidth = 1;
+  // Draw gear teeth
+  const teethCount = 8;
+  const toothWidth = radius * 0.3;
+  const toothHeight = radius * 0.15;
+  for (let i = 0; i < teethCount; i++) {
+    const angle = (i / teethCount) * Math.PI * 2;
+    const x = Math.cos(angle) * radius;
+    const y = Math.sin(angle) * radius;
+    ctx.beginPath();
+    ctx.moveTo(x, y);
+    ctx.lineTo(x + Math.cos(angle) * toothHeight, y + Math.sin(angle) * toothHeight);
+    ctx.lineTo(x + Math.cos(angle + Math.PI / teethCount) * toothHeight, y + Math.sin(angle + Math.PI / teethCount) * toothHeight);
+    ctx.lineTo(x + Math.cos(angle + Math.PI / teethCount) * toothWidth, y + Math.sin(angle + Math.PI / teethCount) * toothWidth);
+    ctx.lineTo(x + Math.cos(angle) * toothWidth, y + Math.sin(angle) * toothWidth);
+    ctx.closePath();
+    ctx.fill();
+    ctx.stroke();
+  }
+  // Draw gear center
+  ctx.beginPath();
+  ctx.arc(0, 0, radius * 0.5, 0, Math.PI * 2);
+  ctx.fillStyle = '#bbbbbb';
+  ctx.fill();
+  ctx.stroke();
+  ctx.restore();
+}
